const [range, setRange] = React.useState({ min: 200, max: 800 });
<RangeSlider
  label="Price range"
  minValue={range.min}
  maxValue={range.max}
  min={0}
  max={1000}
  step={50}
  showValues
  onRangeChange={(lo, hi) => setRange({ min: lo, max: hi })}
/>

